package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testGetDelimiter() throws Exception {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set up the expected delimiter
        char expectedDelimiter = ',';

        // Mock the behavior to return the expected delimiter
        when(csvFormat.getDelimiter()).thenReturn(expectedDelimiter);

        // Invoke the getDelimiter method using reflection
        char actualDelimiter = getDelimiterUsingReflection(csvFormat);

        // Verify the result
        assertEquals(expectedDelimiter, actualDelimiter);
    }

    private char getDelimiterUsingReflection(CSVFormat csvFormat) throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        Method getDelimiterMethod = CSVFormat.class.getDeclaredMethod("getDelimiter");
        getDelimiterMethod.setAccessible(true);
        return (char) getDelimiterMethod.invoke(csvFormat);
    }
}
